43→async function LlmSourcesContent() {
44→  // Récupérer les sources depuis l'API
45→  const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000';
46→
47→  try {
48→    const response = await fetch(`${baseUrl}/api/llm-sources`, {
49→      cache: 'no-store',
50→      headers: {
51→        'Content-Type': 'application/json'
52→      }
53→    });
54→
55→    if (!response.ok) {
56→      throw new Error('Failed to fetch sources');
57→    }
58→
59→    const data = await response.json();
60→
61→    if (!data.success || !data.data || data.data.length === 0) {
62→      return <LlmSourcesEmptyState />;
63→    }
64→
65→    return <LlmSourcesList sources={data.data} />;
66→  } catch (error) {
67→    console.error('Error fetching sources:', error);
68→    return <LlmSourcesEmptyState />;
69→  }
70→}
71→
72→function LoadingSkeleton() {
73→  return (
74→    <div className="space-y-4">
75→      {[1, 2, 3].map((i) => (
76→        <div
77→          key={i}
78→          className="h-32 bg-muted/50 rounded-lg animate-pulse"
79→        />
80→      ))}
81→    </div>
82→  );
83→}
