 26→    const { data: users, error: userError } = await supabase
 27→      .from('users')
 28→      .select('id, clerk_id, subscription_tier')
 29→      .limit(1);
 30→
 31→    if (userError || !users || users.length === 0) {
 32→      return NextResponse.json(
 33→        { success: false, error: 'User not found. Please ensure database is initialized.' } as ApiResponse<never>,
 34→        { status: 404 }
