 36→    }
 37→
 38→    const userId = (users as Array<{ id: string; clerk_id: string; subscription_tier: string }>)[0].id;
 39→
 40→    // Récupérer les sources de l'utilisateur
 41→    const { data: sources, error } = await supabase
 42→      .from('llm_sources')
 43→      .select('*')
