 69→/**
 70→ * POST /api/llm-sources
 71→ * Crée une nouvelle source
 72→ */
 73→export async function POST(request: NextRequest) {
 74→  try {
 75→    const supabase = createServerClient();
 76→
 77→    // Récupérer l'utilisateur (même pattern que GET)
 78→    const { data: users, error: userError } = await supabase
 79→      .from('users')
 80→      .select('id, subscription_tier')
 81→      .limit(1);
 82→
 83→    if (userError || !users || users.length === 0) {
 84→      return NextResponse.json(
 85→        { success: false, error: 'User not found' } as ApiResponse<never>,
 86→        { status: 404 }
 87→      );
 88→    }
 89→
 90→    const typedUsers = users as Array<{ id: string; subscription_tier: string }>;
 91→    const userId = typedUsers[0].id;
 92→    const planTier = typedUsers[0].subscription_tier || 'free';
 93→
 94→    // Parser le body
 95→    const body: LlmSourceFormData = await request.json();
 96→
 97→    if (!body.company_name) {
 98→      return NextResponse.json(
 99→        { success: false, error: 'company_name is required' } as ApiResponse<never>,
100→        { status: 400 }
101→      );
102→    }
103→
104→    // Vérifier les limites du plan
105→    const limits = getPlanLimits(planTier);
106→
107→    // Compter les sources existantes
108→    const { count, error: countError } = await supabase
109→      .from('llm_sources')
110→      .select('id', { count: 'exact', head: true })
111→      .eq('user_id', userId);
112→
113→    if (countError) {
114→      console.error('Error counting sources:', countError);
115→      return NextResponse.json(
116→        { success: false, error: 'Failed to check limits' } as ApiResponse<never>,
117→        { status: 500 }
118→      );
119→    }
120→
121→    // Vérifier si la limite est atteinte
122→    if (isLimitReached(count || 0, limits.maxSources)) {
123→      return NextResponse.json({
124→        success: false,
125→        error: getLimitErrorMessage(planTier, 'maxSources')
126→      } as ApiResponse<never>, { status: 403 });
127→    }
128→
129→    // Générer le slug si non fourni ou si custom slug non autorisé
130→    let slug = body.company_slug;
131→
132→    if (!slug || !limits.customSlug) {
133→      slug = body.company_name
134→        .toLowerCase()
135→        .normalize('NFD')
136→        .replace(/[\u0300-\u036f]/g, '') // Enlever les accents
137→        .replace(/[^a-z0-9]+/g, '-')      // Remplacer non-alphanumeric par -
138→        .replace(/^-|-$/g, '');           // Enlever - au début/fin
139→    }
140→
141→    // Vérifier l'unicité du slug
142→    const { data: existingSlug, error: slugError } = await supabase
143→      .from('llm_sources')
144→      .select('id')
145→      .eq('company_slug', slug)
146→      .maybeSingle();
147→
148→    if (slugError) {
149→      console.error('Error checking slug:', slugError);
150→      return NextResponse.json(
151→        { success: false, error: 'Failed to validate slug' } as ApiResponse<never>,
152→        { status: 500 }
153→      );
154→    }
155→
156→    if (existingSlug) {
157→      // Slug déjà pris, ajouter un suffix
158→      const timestamp = Date.now().toString(36);
159→      slug = `${slug}-${timestamp}`;
160→    }
161→
162→    // Appliquer les limites aux données
163→    const validatedData = enforceDataLimits(body, limits);
164→
165→    // Préparer les données pour l'insertion
166→    const insertData = {
167→      user_id: userId,
168→      company_name: body.company_name,
169→      company_slug: slug,
170→      company_description: body.company_description || null,
171→      company_type: body.company_type || null,
172→      founding_year: body.founding_year || null,
173→      headquarters_city: body.headquarters_city || null,
174→      headquarters_country: body.headquarters_country || null,
175→      website_url: body.website_url || null,
176→      services: validatedData.services || [],
177→      operating_countries: validatedData.operating_countries || [],
178→      languages_supported: validatedData.languages_supported || [],
179→      use_cases: validatedData.use_cases || [],
180→      factual_differentiators: validatedData.factual_differentiators || [],
181→      faq: validatedData.faq || [],
182→      reference_pages: validatedData.reference_pages || [],
183→      official_contacts: validatedData.official_contacts || {},
184→      plan_tier: planTier,
185→      is_published: false, // Par défaut non publié
186→      version: 1,
187→    };
188→
189→    // Insérer dans la base
190→    const { data: newSource, error: insertError } = await supabase
191→      .from('llm_sources')
192→      .insert(insertData as any)
193→      .select()
194→      .single();
195→
196→    if (insertError) {
197→      console.error('Error inserting source:', insertError);
198→      return NextResponse.json(
199→        { success: false, error: 'Failed to create source', message: insertError.message } as ApiResponse<never>,
200→        { status: 500 }
201→      );
202→    }
203→
204→    return NextResponse.json({
205→      success: true,
206→      data: newSource as LlmSource,
207→      message: 'Source created successfully'
208→    } as ApiResponse<LlmSource>, { status: 201 });
209→
210→  } catch (error: any) {
211→    console.error('POST /api/llm-sources error:', error);
212→    return NextResponse.json(
213→      { success: false, error: 'Internal server error', message: error.message } as ApiResponse<never>,
214→      { status: 500 }
215→    );
216→  }
217→}
