 69→/**
 70→ * PUT /api/llm-sources/[id]
 71→ * Met à jour une source
 72→ */
 73→export async function PUT(
 74→  request: NextRequest,
 75→  { params }: { params: { id: string } }
 76→) {
 77→  try {
 78→    const supabase = createServerClient();
 79→    const sourceId = params.id;
 80→
 81→    // Récupérer l'utilisateur
 82→    const { data: users } = await supabase
 83→      .from('users')
 84→      .select('id, subscription_tier')
 85→      .limit(1);
 86→
 87→    if (!users || users.length === 0) {
 88→      return NextResponse.json(
 89→        { success: false, error: 'User not found' } as ApiResponse<never>,
 90→        { status: 404 }
 91→      );
 92→    }
 93→
 94→    const typedUsers = users as Array<{ id: string; subscription_tier: string }>;
 95→    const userId = typedUsers[0].id;
 96→    const planTier = typedUsers[0].subscription_tier || 'free';
 97→
 98→    // Vérifier que la source existe et appartient à l'utilisateur
 99→    const { data: existingSource, error: fetchError } = await supabase
100→      .from('llm_sources')
101→      .select('*')
102→      .eq('id', sourceId)
103→      .eq('user_id', userId)
104→      .single();
105→
106→    if (fetchError || !existingSource) {
107→      return NextResponse.json(
108→        { success: false, error: 'Source not found or access denied' } as ApiResponse<never>,
109→        { status: 404 }
110→      );
111→    }
112→
113→    // Parser le body
114→    const body: Partial<LlmSourceFormData> = await request.json();
115→
116→    // Obtenir les limites du plan
117→    const limits = getPlanLimits(planTier);
118→
119→    // Appliquer les limites aux nouvelles données
120→    const validatedData = enforceDataLimits(body, limits);
121→
122→    // Gérer le slug si modifié
123→    const typedExistingSource = existingSource as LlmSource;
124→    let newSlug = typedExistingSource.company_slug;
125→    if (body.company_slug && limits.customSlug && body.company_slug !== typedExistingSource.company_slug) {
126→      // Vérifier l'unicité
127→      const { data: slugCheck } = await supabase
128→        .from('llm_sources')
129→        .select('id')
130→        .eq('company_slug', body.company_slug)
131→        .neq('id', sourceId)
132→        .maybeSingle();
133→
134→      if (slugCheck) {
135→        return NextResponse.json(
136→          { success: false, error: 'This slug is already taken' } as ApiResponse<never>,
137→          { status: 400 }
138→        );
139→      }
140→
141→      newSlug = body.company_slug;
142→    }
143→
144→    // Préparer les données de mise à jour
145→    const updateData: any = {
146→      updated_at: new Date().toISOString(),
147→    };
148→
149→    // Mettre à jour uniquement les champs fournis
150→    if (body.company_name !== undefined) updateData.company_name = body.company_name;
151→    if (newSlug !== typedExistingSource.company_slug) updateData.company_slug = newSlug;
152→    if (body.company_description !== undefined) updateData.company_description = body.company_description;
153→    if (body.company_type !== undefined) updateData.company_type = body.company_type;
154→    if (body.founding_year !== undefined) updateData.founding_year = body.founding_year;
155→    if (body.headquarters_city !== undefined) updateData.headquarters_city = body.headquarters_city;
156→    if (body.headquarters_country !== undefined) updateData.headquarters_country = body.headquarters_country;
157→    if (body.website_url !== undefined) updateData.website_url = body.website_url;
158→    if (validatedData.services !== undefined) updateData.services = validatedData.services;
159→    if (validatedData.operating_countries !== undefined) updateData.operating_countries = validatedData.operating_countries;
160→    if (validatedData.languages_supported !== undefined) updateData.languages_supported = validatedData.languages_supported;
161→    if (validatedData.use_cases !== undefined) updateData.use_cases = validatedData.use_cases;
162→    if (validatedData.factual_differentiators !== undefined) updateData.factual_differentiators = validatedData.factual_differentiators;
163→    if (validatedData.faq !== undefined) updateData.faq = validatedData.faq;
164→    if (validatedData.reference_pages !== undefined) updateData.reference_pages = validatedData.reference_pages;
165→    if (validatedData.official_contacts !== undefined) updateData.official_contacts = validatedData.official_contacts;
166→
167→    // Mettre à jour dans la base
168→    const { data: updatedSource, error: updateError } = await supabase
169→      .from('llm_sources')
170→      // @ts-ignore - Supabase type inference issue with update operations
171→      .update(updateData)
172→      .eq('id', sourceId)
173→      .eq('user_id', userId)
174→      .select()
175→      .single();
176→
177→    if (updateError) {
178→      console.error('Error updating source:', updateError);
179→      return NextResponse.json(
180→        { success: false, error: 'Failed to update source', message: updateError.message } as ApiResponse<never>,
181→        { status: 500 }
182→      );
183→    }
184→
185→    return NextResponse.json({
186→      success: true,
187→      data: updatedSource as LlmSource,
188→      message: 'Source updated successfully'
189→    } as ApiResponse<LlmSource>);
190→
191→  } catch (error: any) {
192→    console.error('PUT /api/llm-sources/[id] error:', error);
193→    return NextResponse.json(
194→      { success: false, error: 'Internal server error', message: error.message } as ApiResponse<never>,
195→      { status: 500 }
196→    );
197→  }
198→}
