  1→/**
  2→ * API Route pour générer les fichiers llm.json et llm.txt
  3→ * POST: Génère les fichiers et sauvegarde une nouvelle version
  4→ */
  5→
  6→import { NextRequest, NextResponse } from 'next/server';
  7→import { createServerClient } from '@/lib/db/supabase';
  8→import { generateLlmJson, validateLlmJson } from '@/lib/llm-sources/generators/json-generator';
  9→import { generateLlmTxt, validateLlmTxt } from '@/lib/llm-sources/generators/txt-generator';
 10→import { getPlanLimits } from '@/lib/llm-sources/plan-limits';
 11→import type { ApiResponse, GenerateResponse, LlmSource } from '@/types/llm-sources';
 12→
 13→/**
 14→ * POST /api/llm-sources/[id]/generate
 15→ * Génère les fichiers llm.json et llm.txt et crée une nouvelle version
 16→ */
 17→export async function POST(
 18→  request: NextRequest,
 19→  { params }: { params: { id: string } }
 20→) {
 21→  try {
 22→    const supabase = createServerClient();
 23→    const sourceId = params.id;
 24→
 25→    // Récupérer l'utilisateur
 26→    const { data: users } = await supabase
 27→      .from('users')
 28→      .select('id, subscription_tier')
 29→      .limit(1);
 30→
 31→    if (!users || users.length === 0) {
 32→      return NextResponse.json(
 33→        { success: false, error: 'User not found' } as ApiResponse<never>,
 34→        { status: 404 }
 35→      );
 36→    }
 37→
 38→    const typedUsers = users as Array<{ id: string; subscription_tier: string }>;
 39→    const userId = typedUsers[0].id;
 40→    const planTier = typedUsers[0].subscription_tier || 'free';
 41→
 42→    // Vérifier les limites du plan
 43→    const limits = getPlanLimits(planTier);
 44→
 45→    if (!limits.autoGeneration) {
 46→      return NextResponse.json({
 47→        success: false,
 48→        error: 'Auto-generation is not available on your plan. Please upgrade to Pro or Agency.',
 49→        upgradeRequired: true
 50→      } as ApiResponse<never>, { status: 403 });
 51→    }
 52→
 53→    // Récupérer la source
 54→    const { data: source, error: sourceError } = await supabase
 55→      .from('llm_sources')
 56→      .select('*')
 57→      .eq('id', sourceId)
 58→      .eq('user_id', userId)
 59→      .single();
 60→
 61→    if (sourceError || !source) {
 62→      return NextResponse.json(
 63→        { success: false, error: 'Source not found or access denied' } as ApiResponse<never>,
 64→        { status: 404 }
 65→      );
 66→    }
 67→
 68→    const typedSource = source as LlmSource;
 69→
 70→    // Générer les fichiers
 71→    let jsonContent, txtContent;
 72→
 73→    try {
 74→      jsonContent = generateLlmJson(typedSource);
 75→      validateLlmJson(jsonContent);
 76→    } catch (error: any) {
 77→      console.error('Error generating JSON:', error);
 78→      return NextResponse.json(
 79→        { success: false, error: 'Failed to generate JSON file', message: error.message } as ApiResponse<never>,
 80→        { status: 500 }
 81→      );
 82→    }
 83→
 84→    try {
 85→      txtContent = generateLlmTxt(typedSource);
 86→      validateLlmTxt(txtContent);
 87→    } catch (error: any) {
 88→      console.error('Error generating TXT:', error);
 89→      return NextResponse.json(
 90→        { success: false, error: 'Failed to generate TXT file', message: error.message } as ApiResponse<never>,
 91→        { status: 500 }
 92→      );
 93→    }
 94→
 95→    // Incrémenter la version
 96→    const newVersion = typedSource.version + 1;
 97→
 98→    // Sauvegarder la version (si versionHistory activé)
 99→    if (limits.versionHistory) {
100→      const { error: versionError } = await supabase
101→        .from('llm_source_versions')
102→        .insert({
103→          llm_source_id: sourceId,
104→          version: newVersion,
105→          json_content: jsonContent,
106→          txt_content: txtContent,
107→          generated_by: 'user' // ou 'auto' si c'est automatique
108→        } as any);
109→
110→      if (versionError) {
111→        console.error('Error saving version:', versionError);
112→        // On continue quand même, ce n'est pas bloquant
113→      }
114→    }
115→
116→    // Mettre à jour la source avec la nouvelle version et timestamp
117→    const { error: updateError } = await supabase
118→      .from('llm_sources')
119→      // @ts-ignore - Supabase type inference issue with update operations
120→      .update({
121→        version: newVersion,
122→        last_generated_at: new Date().toISOString(),
123→        updated_at: new Date().toISOString()
124→      })
125→      .eq('id', sourceId);
126→
127→    if (updateError) {
128→      console.error('Error updating source:', updateError);
129→      // Non bloquant, on retourne quand même les fichiers
130→    }
131→
132→    // Construire les URLs publiques
133→    const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000';
134→    const urls = {
135→      json: `${baseUrl}/directory/${typedSource.company_slug}/llm.json`,
136→      txt: `${baseUrl}/directory/${typedSource.company_slug}/llm.txt`
137→    };
138→
139→    const response: GenerateResponse = {
140→      version: newVersion,
141→      json: jsonContent,
142→      txt: txtContent,
143→      urls
144→    };
145→
146→    return NextResponse.json({
147→      success: true,
148→      data: response,
149→      message: 'Files generated successfully'
150→    } as ApiResponse<GenerateResponse>, { status: 200 });
151→
152→  } catch (error: any) {
153→    console.error('POST /api/llm-sources/[id]/generate error:', error);
154→    return NextResponse.json(
155→      { success: false, error: 'Internal server error', message: error.message } as ApiResponse<never>,
156→      { status: 500 }
157→    );
158→  }
159→}
