  1→/**
  2→ * Endpoint public pour servir le fichier llm.json
  3→ * GET: Retourne le fichier JSON généré pour une organisation publiée
  4→ */
  5→
  6→import { NextRequest, NextResponse } from 'next/server';
  7→import { createPublicClient } from '@/lib/db/supabase';
  8→import { generateLlmJson } from '@/lib/llm-sources/generators/json-generator';
  9→import type { LlmSource } from '@/types/llm-sources';
 10→
 11→/**
 12→ * GET /directory/[slug]/llm.json
 13→ * Endpoint public accessible sans authentification
 14→ */
 15→export async function GET(
 16→  request: NextRequest,
 17→  { params }: { params: { slug: string } }
 18→) {
 19→  try {
 20→    const supabase = createPublicClient();
 21→    const slug = params.slug;
 22→
 23→    // Récupérer la source publiée avec ce slug
 24→    const { data: source, error } = await supabase
 25→      .from('llm_sources')
 26→      .select('*')
 27→      .eq('company_slug', slug)
 28→      .eq('is_published', true)
 29→      .single();
 30→
 31→    if (error || !source) {
 32→      return NextResponse.json(
 33→        {
 34→          error: 'Source not found or not published',
 35→          message: 'This organization has not published their LLM source data yet.'
 36→        },
 37→        {
 38→          status: 404,
 39→          headers: {
 40→            'Content-Type': 'application/json',
 41→            'Cache-Control': 'public, max-age=300, s-maxage=600' // Cache 5min/10min
 42→          }
 43→        }
 44→      );
 45→    }
 46→
 47→    const typedSource = source as LlmSource;
 48→
 49→    // Générer le JSON à la volée (ou récupérer depuis versions si disponible)
 50→    let jsonContent;
 51→
 52→    try {
 53→      // Essayer de récupérer la dernière version générée
 54→      const { data: latestVersion } = await supabase
 55→        .from('llm_source_versions')
 56→        .select('json_content')
 57→        .eq('llm_source_id', typedSource.id)
 58→        .order('version', { ascending: false })
 59→        .limit(1)
 60→        .maybeSingle();
 61→
 62→      const typedVersion = latestVersion as { json_content: any } | null;
 63→      if (typedVersion && typedVersion.json_content) {
 64→        jsonContent = typedVersion.json_content;
 65→      } else {
 66→        // Générer à la volée si pas de version sauvegardée
 67→        jsonContent = generateLlmJson(typedSource);
 68→      }
 69→    } catch (genError) {
 70→      console.error('Error getting/generating JSON:', genError);
 71→      // Fallback : générer à la volée
 72→      jsonContent = generateLlmJson(typedSource);
 73→    }
 74→
 75→    // Logger l'accès (optionnel, pour analytics)
 76→    logAccess(slug, 'json', request).catch(err =>
 77→      console.error('Error logging access:', err)
 78→    );
 79→
 80→    // Retourner le JSON avec headers optimisés
 81→    return NextResponse.json(jsonContent, {
 82→      status: 200,
 83→      headers: {
 84→        'Content-Type': 'application/json; charset=utf-8',
 85→        'Cache-Control': 'public, max-age=3600, s-maxage=7200', // Cache 1h/2h
 86→        'X-Data-Version': String(typedSource.version),
 87→        'X-Generated-At': typedSource.last_generated_at || new Date().toISOString(),
 88→        'Access-Control-Allow-Origin': '*', // CORS permissif pour accès public
 89→        'Access-Control-Allow-Methods': 'GET, OPTIONS',
 90→        'Access-Control-Allow-Headers': 'Content-Type'
 91→      }
 92→    });
 93→
 94→  } catch (error) {
 95→    console.error('GET /directory/[slug]/llm.json error:', error);
 96→    return NextResponse.json(
 97→      {
 98→        error: 'Internal server error',
 99→        message: 'An error occurred while retrieving the data.'
100→      },
101→      {
102→        status: 500,
103→        headers: {
104→          'Content-Type': 'application/json'
105→        }
106→      }
107→    );
108→  }
109→}
