  1→/**
  2→ * Endpoint public pour servir le fichier llm.txt
  3→ * GET: Retourne le fichier TXT généré pour une organisation publiée
  4→ */
  5→
  6→import { NextRequest, NextResponse } from 'next/server';
  7→import { createPublicClient } from '@/lib/db/supabase';
  8→import { generateLlmTxt } from '@/lib/llm-sources/generators/txt-generator';
  9→import type { LlmSource } from '@/types/llm-sources';
 10→
 11→/**
 12→ * GET /directory/[slug]/llm.txt
 13→ * Endpoint public accessible sans authentification
 14→ */
 15→export async function GET(
 16→  request: NextRequest,
 17→  { params }: { params: { slug: string } }
 18→) {
 19→  try {
 20→    const supabase = createPublicClient();
 21→    const slug = params.slug;
 22→
 23→    // Récupérer la source publiée avec ce slug
 24→    const { data: source, error } = await supabase
 25→      .from('llm_sources')
 26→      .select('*')
 27→      .eq('company_slug', slug)
 28→      .eq('is_published', true)
 29→      .single();
 30→
 31→    if (error || !source) {
 32→      return new NextResponse(
 33→        'Source not found or not published.\nThis organization has not published their LLM source data yet.',
 34→        {
 35→          status: 404,
 36→          headers: {
 37→            'Content-Type': 'text/plain; charset=utf-8',
 38→            'Cache-Control': 'public, max-age=300' // Cache 5min
 39→          }
 40→        }
 41→      );
 42→    }
 43→
 44→    const typedSource = source as LlmSource;
 45→
 46→    // Générer le TXT à la volée (ou récupérer depuis versions si disponible)
 47→    let txtContent;
 48→
 49→    try {
 50→      // Essayer de récupérer la dernière version générée
 51→      const { data: latestVersion } = await supabase
 52→        .from('llm_source_versions')
 53→        .select('txt_content')
 54→        .eq('llm_source_id', typedSource.id)
 55→        .order('version', { ascending: false })
 56→        .limit(1)
 57→        .maybeSingle();
 58→
 59→      const typedVersion = latestVersion as { txt_content: string } | null;
 60→      if (typedVersion && typedVersion.txt_content) {
 61→        txtContent = typedVersion.txt_content;
 62→      } else {
 63→        // Générer à la volée si pas de version sauvegardée
 64→        txtContent = generateLlmTxt(typedSource);
 65→      }
 66→    } catch (genError) {
 67→      console.error('Error getting/generating TXT:', genError);
 68→      // Fallback : générer à la volée
 69→      txtContent = generateLlmTxt(typedSource);
 70→    }
 71→
 72→    // Logger l'accès (optionnel, pour analytics)
 73→    logAccess(slug, 'txt', request).catch(err =>
 74→      console.error('Error logging access:', err)
 75→    );
 76→
 77→    // Retourner le TXT avec headers optimisés
 78→    return new NextResponse(txtContent, {
 79→      status: 200,
 80→      headers: {
 81→        'Content-Type': 'text/plain; charset=utf-8',
 82→        'Cache-Control': 'public, max-age=3600, s-maxage=7200', // Cache 1h/2h
 83→        'X-Data-Version': String(typedSource.version),
 84→        'X-Generated-At': typedSource.last_generated_at || new Date().toISOString(),
 85→        'Access-Control-Allow-Origin': '*', // CORS permissif pour accès public
 86→        'Access-Control-Allow-Methods': 'GET, OPTIONS',
 87→        'Access-Control-Allow-Headers': 'Content-Type',
 88→        // Headers pour forcer le téléchargement si nécessaire
 89→        'Content-Disposition': `inline; filename="${slug}-llm.txt"`
 90→      }
 91→    });
 92→
 93→  } catch (error) {
 94→    console.error('GET /directory/[slug]/llm.txt error:', error);
 95→    return new NextResponse(
 96→      'Internal server error.\nAn error occurred while retrieving the data.',
 97→      {
 98→        status: 500,
 99→        headers: {
100→          'Content-Type': 'text/plain; charset=utf-8'
101→        }
102→      }
103→    );
104→  }
105→}
