107→/**
108→ * OPTIONS handler pour CORS preflight
109→ */
110→export async function OPTIONS() {
111→  return new NextResponse(null, {
112→    status: 204,
113→    headers: {
114→      'Access-Control-Allow-Origin': '*',
115→      'Access-Control-Allow-Methods': 'GET, OPTIONS',
116→      'Access-Control-Allow-Headers': 'Content-Type',
117→      'Access-Control-Max-Age': '86400' // 24h
118→    }
119→  });
120→}
